const flags = $('Prepare Retrieval').first().json || {};
const n = $('Normalize Input').first().json || {};
const question = n.question || '';
const history = Array.isArray(n.history) ? n.history : [];
const NL = String.fromCharCode(10);
const historyText = history.map(m => (m.role === 'assistant' ? 'Assistant: ' : 'User: ') + (m.content || '')).join(NL);
const TOPK = 20;

const rows = [];
const all = $input.all();
for (let i = 0; i < all.length; i++) {
  const j = all[i].json || {};
  if (j.isChatDoc === true) {
    rows.push({ text: String(j.text || '').slice(0, 100000), filename: j.filename || '', isLibrary: false });
  } else if (j.driveFileId && j.text != null) {
    rows.push({ text: String(j.text).slice(0, 24000), filename: j.filename || '', isLibrary: true });
  }
}
const chat = rows.filter(r => !r.isLibrary);
const lib = rows.filter(r => r.isLibrary);

let chosen = chat.concat(lib);
const seen = new Set();
chosen = chosen.filter(r => { const k = (r.filename || '') + '#' + (r.text || '').slice(0, 60); if (seen.has(k)) return false; seen.add(k); return true; }).slice(0, TOPK);

const sources = [], contextParts = [];
for (const r of chosen) {
  const origin = r.isLibrary ? 'Drive' : 'This chat';
  contextParts.push('[' + (contextParts.length + 1) + '] (' + origin + ' · ' + r.filename + ') ' + r.text);
  sources.push({ filename: r.filename, chunkIndex: 0, text: r.text, origin });
}
return [{ json: { question, context: contextParts.length ? contextParts.join(NL + NL) : '', sources, historyText } }];

const j = $input.first().json || {};
let answer = '';
if (j.text != null) { answer = j.text; }
else if (j.output != null) { answer = j.output; }
else if (j.response != null) { answer = j.response; }
const sources = $('Build Context and Sources').first().json.sources || [];
return [{ json: { answer: answer, sources: sources } }];

let useDrive = false;
const c = $input.first().json;
const content = (c && c.choices && c.choices[0] && c.choices[0].message && c.choices[0].message.content) || '';
const s = String(content); const a = s.indexOf('{'); const b = s.lastIndexOf('}');
if (a >= 0 && b > a) { try { const o = JSON.parse(s.slice(a, b + 1)); useDrive = o.useDrive === true; } catch (e) {} }
const n = $('Normalize Input').first().json;
const hasFile = Array.isArray(n.docs) && n.docs.length > 0;
return [{ json: { conversationId: n.conversationId, question: n.question, history: n.history, hasFile: hasFile, useDrive: useDrive } }];

const docs = $('Normalize Input').first().json.docs || [];
const rows = docs.map(d => ({ json: { filename: d.filename || '', text: d.text || '', isChatDoc: true } }));
return rows.length ? rows : [{ json: { placeholder: true } }];
